B.aiH=new A.iP(B.UP,"Kendi hayat\u0131n\u0131n sahibi olmak","Kontrol\xfc kaybetmek, zay\u0131f g\xf6r\xfcnmek","Meydan Okuyanlar d\xfcnyay\u0131 g\xfc\xe7 dengesi olarak okur. Yumu\u015fakl\u0131\u011fa izin verdiklerinde ger\xe7ek liderlik ortaya \xe7\u0131kar.")
