B.SK=new A.qE("Gizlilik Politikas\u0131",null)
B.Sx=new A.cb("Gizlilik Politikas\u0131","Bilka Enneagram olarak ki\u015fisel verilerinizin gizlili\u011fini \xf6nemsiyoruz. Bu politika, web sitemizi ziyaret etti\u011finizde veya test hizmetimizi kulland\u0131\u011f\u0131n\u0131zda toplanan, i\u015flenen ve korunan veriler hakk\u0131nda sizi bilgilendirmek amac\u0131yla haz\u0131rlanm\u0131\u015ft\u0131r.","Son g\xfcncelleme: Ocak 2025",!0)
B.Sh=new A.cb("1. Toplanan Veriler","Hizmetlerimizi kullanman\u0131z s\u0131ras\u0131nda a\u015fa\u011f\u0131daki ki\u015fisel veriler toplanabilir:\n\n\u2022 Ad ve soyad\n\u2022 E-posta adresi\n\u2022 Telefon numaras\u0131\n\u2022 Do\u011fum tarihi\n\u2022 Enneagram testi cevaplar\u0131 ve sonu\xe7lar\u0131\n\u2022 \u0130leti\u015fim formu i\xe7erikleri\n\nBu veriler yaln\u0131zca sa\u011flanan hizmetin sunulmas\u0131 amac\u0131yla kullan\u0131l\u0131r.",null,!1)
B.So=new A.cb("2. Veri \u0130\u015fleme Amac\u0131","Toplanan veriler \u015fu ama\xe7larla i\u015flenir:\n\n\u2022 Enneagram testinin de\u011ferlendirilmesi ve sonu\xe7lar\u0131n hesaplanmas\u0131\n\u2022 Miza\xe7 dan\u0131\u015fmanl\u0131\u011f\u0131 randevular\u0131n\u0131n d\xfczenlenmesi\n\u2022 \u0130leti\u015fim taleplerinize yan\u0131t verilmesi\n\u2022 Hizmet kalitesinin art\u0131r\u0131lmas\u0131\n\u2022 Yasal y\xfck\xfcml\xfcl\xfcklerin yerine getirilmesi",null,!1)
B.Sq=new A.cb("3. Veri Payla\u015f\u0131m\u0131","Ki\u015fisel verileriniz, a\xe7\u0131k r\u0131zan\u0131z olmadan \xfc\xe7\xfcnc\xfc taraflarla payla\u015f\u0131lmaz. Yaln\u0131zca \u015fu durumlarda payla\u015f\u0131m yap\u0131labilir:\n\n\u2022 Yasal zorunluluk bulunmas\u0131 halinde yetkili kamu kurum ve kurulu\u015flar\u0131yla\n\u2022 Hizmetin sunulmas\u0131 i\xe7in zorunlu teknik altyap\u0131 sa\u011flay\u0131c\u0131lar\u0131yla (gizlilik s\xf6zle\u015fmesi kapsam\u0131nda)",null,!1)
B.SA=new A.cb("4. Veri Saklama S\xfcresi","Verileriniz, hizmet ili\u015fkisinin sona ermesinden itibaren yasal saklama y\xfck\xfcml\xfcl\xfckleri do\u011frultusunda en fazla 3 y\u0131l s\xfcreyle saklan\u0131r. Bu s\xfcre sonunda verileriniz g\xfcvenli bi\xe7imde silinir veya anonimle\u015ftirilir.",null,!1)
B.Ss=new A.cb("5. G\xfcvenlik","Ki\u015fisel verilerinizin g\xfcvenli\u011fi i\xe7in end\xfcstri standard\u0131 teknik ve idari \xf6nlemler uygulanmaktad\u0131r. Veriler \u015fifreli ba\u011flant\u0131lar \xfczerinden iletilir ve g\xfcvenli sunucularda saklan\u0131r.",null,!1)
B.Sk=new A.cb("6. Haklar\u0131n\u0131z (KVKK)","Ki\u015fisel Verilerin Korunmas\u0131 Kanunu kapsam\u0131nda a\u015fa\u011f\u0131daki haklara sahipsiniz:\n\n\u2022 Verilerinizin i\u015flenip i\u015flenmedi\u011fini \xf6\u011frenme\n\u2022 \u0130\u015flenmi\u015fse buna ili\u015fkin bilgi talep etme\n\u2022 Yanl\u0131\u015f verilerin d\xfczeltilmesini isteme\n\u2022 Ko\u015fullar olu\u015ftu\u011funda silinmesini talep etme\n\u2022 \u0130\u015flemeye itiraz etme\n\nBu haklar\u0131n\u0131z\u0131 kullanmak i\xe7in a\u015fa\u011f\u0131daki adrese ba\u015fvurabilirsiniz.",null,!1)
B.Sl=new A.cb("7. \u0130leti\u015fim","Gizlilik politikam\u0131zla ilgili sorular\u0131n\u0131z i\xe7in:\n\nBilka Enneagram\nE-posta: info@bilkaenneagram.com.tr\nTelefon: +90 (555) 000 00 00",null,!1)
