B.aaL=new A.kQ("Hizmetlerimiz","Size nas\u0131l ","yard\u0131mc\u0131"," olabiliriz?","Miza\xe7 odakl\u0131 bireysel ve kurumsal geli\u015fim i\xe7in kapsaml\u0131 hizmet se\xe7enekleri sunuyoruz.",B.bO,null)
B.aaM=new A.kQ("S\u0131k Sorulan Sorular","Merak ettikleriniz, ","net cevaplar.",null,"Enneagram ve Bilka Enneagram testi hakk\u0131nda en s\u0131k ald\u0131\u011f\u0131m\u0131z sorular\u0131 derledik.",B.co,null)
B.aaN=new A.kQ("9 Miza\xe7 Tipi","9 temel aray\u0131\u015f, ","9 miza\xe7"," tipi.","Enneagram'a g\xf6re insanlar en temelde 9 nefs kategorisine ayr\u0131l\u0131r. Bu bir etiketleme de\u011fil, var olan\u0131 en nesnel haliyle ortaya koymakt\u0131r.",B.bO,null)
B.aaO=new A.kQ("Hakk\u0131m\u0131zda","D\xfcnyada ender rastlanan bir ","akademik"," \xe7al\u0131\u015fma.","Bilka Enneagram, ki\u015filik tiplerini en nesnel ve g\xfcvenilir \u015fekilde ortaya koymay\u0131 hedefleyen \xf6zg\xfcn bir test sistemidir.",B.bO,null)
B.aaP=new A.kQ("\u0130leti\u015fim","Bizimle ileti\u015fime ","ge\xe7in.",null,"Test hakk\u0131nda sorular\u0131n\u0131z i\xe7in veya miza\xe7 dan\u0131\u015fmanl\u0131\u011f\u0131 randevusu almak i\xe7in bize ula\u015fabilirsiniz.",B.bO,null)
B.aaQ=new A.kQ("Neden Bilka Enneagram?","Akademik g\xfcvenilirlik,\n","k\xfclt\xfcrel"," duyarl\u0131l\u0131k.","Testin her maddesi, binin \xfczerinde kat\u0131l\u0131mc\u0131yla denenerek en y\xfcksek do\u011fruluk skorunu elde eden sorulardan se\xe7ilmi\u015ftir.",B.bO,null)
B.aaR=new A.kQ("Blog & \u0130\xe7g\xf6r\xfcler","Miza\xe7 \xfczerine ","yaz\u0131lar.",null,"Enneagram'\u0131n g\xfcnl\xfck ya\u015fama, ili\u015fkilere ve kariyere dair pratik yans\u0131malar\u0131n\u0131 derleyen yaz\u0131lar.",B.bO,null)
